import React from "react";

export default function WeatherOverlay({ condition, isDaytime }) {
  // Normalize the condition to lowercase
  const weather = condition?.toLowerCase() || "";

  // Decide which gif to use
  let gif = "";

  if (weather.includes("rain") && !isDaytime) gif = "rainNight.gif";
  else if (weather.includes("rain")) gif = "rain.gif";
  else if (weather.includes("snow")) gif = "snow.gif";
  else if (weather.includes("thunder")) gif = "thunderstorm.gif";
  else if (weather.includes("cloud") && !isDaytime) gif = "PCnight.gif";
  else if (weather.includes("cloud") && isDaytime) gif = "PCday.gif";
  else if (weather.includes("wind")) gif = "Windy-Weather-App.gif";
  else if (isDaytime) gif = "sunset.gif";
  else gif = "night.gif";

  return (
    <div className="absolute top-0 left-0 w-full h-full z-0 pointer-events-none overflow-hidden">
      <img
        src={`/overlays/${gif}`}
        alt="weather overlay"
        className="w-full h-full object-cover opacity-70"
      />
    </div>
  );
}
